<?php
namespace Database\Seeders;use App\Models\User;use Illuminate\Database\Seeder;use Spatie\Permission\Models\Permission;use Spatie\Permission\Models\Role;
class RolePermissionSeeder extends Seeder{public function run():void{app(\Spatie\Permission\PermissionRegistrar::class)->forgetCachedPermissions();$permissions=['manage-master','manage-users','manage-questions','manage-schedules','monitor-exams','grade-essays','view-reports','take-exams'];foreach($permissions as $p)Permission::findOrCreate($p,'web');$map=['SuperAdmin'=>$permissions,'Admin'=>['manage-master','manage-users','manage-schedules','view-reports'],'Guru'=>['manage-questions','grade-essays','view-reports'],'Pengawas'=>['monitor-exams'],'Siswa'=>['take-exams']];foreach($map as $name=>$perms){$role=Role::findOrCreate($name,'web');$role->syncPermissions($perms);foreach(User::where('role',$name)->get() as $u)$u->syncRoles([$role]);}}}